Here is the comprehensive setup to migrate your MileMaster SG app to Supabase.

### 1. SQL Database Setup
Run the following SQL in your Supabase project's **SQL Editor** to create the necessary tables, security policies (RLS), and storage buckets.

```sql
-- 1. Create Profiles Table (Users)
create table public.profiles (
  id uuid references auth.users on delete cascade not null primary key,
  email text not null,
  name text,
  role text default 'user',
  status text default 'active',
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- 2. Create Bills Table
create table public.bills (
  id uuid default gen_random_uuid() primary key,
  user_id uuid references public.profiles(id) on delete cascade not null,
  bank_name text not null,
  card_name text not null,
  statement_date date,
  due_date date,
  total_amount numeric not null,
  is_paid boolean default false,
  payment_method text,
  payment_date timestamp with time zone,
  transaction_ref text,
  file_path text, -- Path to file in Storage
  risk_score numeric default 0,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- 3. Create Transactions Table
create table public.transactions (
  id uuid default gen_random_uuid() primary key,
  bill_id uuid references public.bills(id) on delete cascade not null,
  date date,
  description text,
  amount numeric,
  category text,
  suggested_card text,
  created_at timestamp with time zone default timezone('utc'::text, now()) not null
);

-- 4. Create System Config Table (Singleton)
create table public.system_config (
  id integer primary key default 1,
  allow_signups boolean default true,
  hero_title text,
  hero_subtitle text,
  bullets text[],
  updated_at timestamp with time zone default timezone('utc'::text, now())
);

-- Insert default config
insert into public.system_config (id, allow_signups, hero_title, hero_subtitle, bullets)
values (1, true, 'Maximize your miles.\nMinimize the hassle.', 'The AI-powered bill tracker designed for Singaporean credit card strategists.', ARRAY['Auto-extract data from PDF statements', 'Spend trend analysis by bank', 'Singapore-Crowd Source Mile Strategies']);

-- 5. Enable Row Level Security (RLS)
alter table public.profiles enable row level security;
alter table public.bills enable row level security;
alter table public.transactions enable row level security;
alter table public.system_config enable row level security;

-- 6. RLS Policies
-- Profiles: Users can see themselves, Admin can see all
create policy "Public profiles are viewable by everyone" on profiles for select using (true);
create policy "Users can insert their own profile" on profiles for insert with check (auth.uid() = id);
create policy "Users can update own profile" on profiles for update using (auth.uid() = id);

-- Bills: Users can only see/edit their own
create policy "Users can see own bills" on bills for select using (auth.uid() = user_id);
create policy "Users can insert own bills" on bills for insert with check (auth.uid() = user_id);
create policy "Users can update own bills" on bills for update using (auth.uid() = user_id);
create policy "Users can delete own bills" on bills for delete using (auth.uid() = user_id);

-- Transactions: Inherit from bill ownership
create policy "Users can see own transactions" on transactions for select using (
  exists (select 1 from bills where bills.id = transactions.bill_id and bills.user_id = auth.uid())
);
create policy "Users can insert own transactions" on transactions for insert with check (
  exists (select 1 from bills where bills.id = bill_id and bills.user_id = auth.uid())
);

-- System Config: Public read, Admin write (mocking admin check for simplicity)
create policy "Config is public" on system_config for select using (true);
create policy "Admins can update config" on system_config for update using (
  exists (select 1 from profiles where id = auth.uid() and role = 'admin')
);

-- 7. Storage Bucket Setup
insert into storage.buckets (id, name, public) values ('bill-documents', 'bill-documents', false);

-- Storage Policies
create policy "Users can upload own bills" on storage.objects for insert with check (
  bucket_id = 'bill-documents' and auth.uid()::text = (storage.foldername(name))[1]
);
create policy "Users can view own bills" on storage.objects for select using (
  bucket_id = 'bill-documents' and auth.uid()::text = (storage.foldername(name))[1]
);
```

### 2. Application Updates

I will now update your application to use the Supabase SDK instead of `localStorage`.

