import { createClient } from '@supabase/supabase-js';

const supabaseUrl = 'https://gaxfdvmqgflsqommdeth.supabase.co';
const supabaseKey = 'sb_publishable_3Qswi2JBeIo7163whoCAoA_dqDi8gAx';

export const supabase = createClient(supabaseUrl, supabaseKey);

import { supabase } from '../lib/supabaseClient';
import { Bill, Transaction, SystemConfig, PaymentDetails } from '../types';

export const dbService = {
  // --- Bills ---
  async getBills(userId: string): Promise<Bill[]> {
    const { data, error } = await supabase
      .from('bills')
      .select(`
        *,
        transactions (*)
      `)
      .eq('user_id', userId)
      .order('due_date', { ascending: true });

    if (error) throw error;

    return data.map((b: any) => ({
      id: b.id,
      bankName: b.bank_name,
      cardName: b.card_name,
      statementDate: b.statement_date,
      dueDate: b.due_date,
      totalAmount: b.total_amount,
      isPaid: b.is_paid,
      uploadedAt: b.created_at,
      riskScore: b.risk_score,
      paymentDetails: b.is_paid ? {
        paidAt: b.payment_date,
        transactionId: b.transaction_ref,
        method: b.payment_method as any
      } : undefined,
      transactions: b.transactions.map((t: any) => ({
        id: t.id,
        date: t.date,
        description: t.description,
        amount: t.amount,
        category: t.category,
        suggestedCard: t.suggested_card
      }))
    }));
  },

  async createBill(bill: Bill, userId: string, file?: File): Promise<Bill> {
    let filePath = null;

    // 1. Upload File if exists
    if (file) {
      const fileExt = file.name.split('.').pop();
      const fileName = `${userId}/${crypto.randomUUID()}.${fileExt}`;
      const { error: uploadError } = await supabase.storage
        .from('bill-documents')
        .upload(fileName, file);

      if (uploadError) console.error('Upload failed', uploadError);
      else filePath = fileName;
    }

    // 2. Insert Bill
    const { data: billData, error: billError } = await supabase
      .from('bills')
      .insert({
        user_id: userId,
        bank_name: bill.bankName,
        card_name: bill.cardName,
        statement_date: bill.statementDate,
        due_date: bill.dueDate,
        total_amount: bill.totalAmount,
        is_paid: bill.isPaid,
        file_path: filePath,
        risk_score: bill.riskScore
      })
      .select()
      .single();

    if (billError) throw billError;

    // 3. Insert Transactions
    if (bill.transactions.length > 0) {
      const transactionsPayload = bill.transactions.map(t => ({
        bill_id: billData.id,
        date: t.date,
        description: t.description,
        amount: t.amount,
        category: t.category,
        suggested_card: t.suggestedCard
      }));

      const { error: txError } = await supabase
        .from('transactions')
        .insert(transactionsPayload);

      if (txError) throw txError;
    }

    // Return the formatted bill (re-using getBills logic or constructing manually)
    // For simplicity, constructing manually but ensuring ID matches DB
    return { ...bill, id: billData.id };
  },

  async updateBill(bill: Bill): Promise<void> {
    const { error } = await supabase
      .from('bills')
      .update({
        bank_name: bill.bankName,
        card_name: bill.cardName,
        total_amount: bill.totalAmount,
        due_date: bill.dueDate,
        statement_date: bill.statementDate,
        is_paid: bill.isPaid,
        payment_date: bill.paymentDetails?.paidAt,
        payment_method: bill.paymentDetails?.method,
        transaction_ref: bill.paymentDetails?.transactionId
      })
      .eq('id', bill.id);

    if (error) throw error;
  },

  // --- System Config ---
  async getSystemConfig(): Promise<SystemConfig | null> {
    const { data, error } = await supabase
      .from('system_config')
      .select('*')
      .single();

    if (error) return null;

    return {
      allowSignups: data.allow_signups,
      landingPage: {
        heroTitle: data.hero_title,
        heroSubtitle: data.hero_subtitle,
        bullets: data.bullets || []
      }
    };
  },

  async updateSystemConfig(config: SystemConfig): Promise<void> {
    const { error } = await supabase
      .from('system_config')
      .update({
        allow_signups: config.allowSignups,
        hero_title: config.landingPage.heroTitle,
        hero_subtitle: config.landingPage.heroSubtitle,
        bullets: config.landingPage.bullets
      })
      .eq('id', 1);

    if (error) throw error;
  }
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { User, SystemConfig } from '../types';
import { supabase } from '../lib/supabaseClient';
import { dbService } from '../services/dbService';

interface AuthContextType {
  user: User | null;
  systemConfig: SystemConfig;
  login: (email: string, password: string) => Promise<void>;
  signup: (name: string, email: string, password: string) => Promise<void>;
  logout: () => void;
  loading: boolean;
  getAllUsers: () => Promise<User[]>;
  toggleUserStatus: (userId: string) => Promise<void>;
  updateSystemConfig: (config: SystemConfig) => Promise<void>;
  changePassword: (password: string) => Promise<void>;
}

const DEFAULT_CONFIG: SystemConfig = {
  allowSignups: true,
  landingPage: {
    heroTitle: "Maximize your miles.\nMinimize the hassle.",
    heroSubtitle: "The AI-powered bill tracker designed for Singaporean credit card strategists.",
    bullets: ["Auto-extract data", "Trend analysis", "Miles Strategies"]
  }
};

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [systemConfig, setSystemConfig] = useState<SystemConfig>(DEFAULT_CONFIG);

  useEffect(() => {
    // Initial Load
    const init = async () => {
      // 1. Load System Config
      const config = await dbService.getSystemConfig();
      if (config) setSystemConfig(config);

      // 2. Check Session
      const { data: { session } } = await supabase.auth.getSession();
      if (session?.user) {
        await fetchProfile(session.user.id, session.user.email!);
      }
      setLoading(false);
    };

    init();

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (event === 'SIGNED_IN' && session?.user) {
        await fetchProfile(session.user.id, session.user.email!);
      } else if (event === 'SIGNED_OUT') {
        setUser(null);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchProfile = async (uid: string, email: string) => {
    const { data, error } = await supabase
      .from('profiles')
      .select('*')
      .eq('id', uid)
      .single();

    if (data) {
        setUser({
            id: data.id,
            email: data.email,
            name: data.name,
            role: data.role as 'admin' | 'user',
            joinedAt: data.created_at,
            status: data.status as 'active' | 'suspended'
        });
    } else {
        // Handle edge case where auth exists but profile doesn't (legacy/error)
        // For now, simple fallback
        setUser({ id: uid, email, name: 'User', role: 'user', joinedAt: new Date().toISOString(), status: 'active' });
    }
  };

  const login = async (email: string, password: string) => {
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
  };

  const signup = async (name: string, email: string, password: string) => {
    if (!systemConfig.allowSignups) throw new Error("Registrations disabled.");

    const { data, error } = await supabase.auth.signUp({
      email,
      password,
      options: { data: { name } } // Supabase trigger handles profile creation usually, but we can manual insert if needed
    });

    if (error) throw error;

    if (data.user) {
        // Manually create profile if no Trigger is set up in SQL
        await supabase.from('profiles').insert({
            id: data.user.id,
            email: email,
            name: name,
            role: 'user'
        });
    }
  };

  const logout = async () => {
    await supabase.auth.signOut();
  };

  // --- Admin Functions ---
  const getAllUsers = async (): Promise<User[]> => {
      const { data, error } = await supabase.from('profiles').select('*');
      if (error) throw error;
      return data.map((u: any) => ({
          id: u.id,
          email: u.email,
          name: u.name,
          role: u.role,
          status: u.status,
          joinedAt: u.created_at
      }));
  };

  const toggleUserStatus = async (userId: string) => {
      // Fetch current status first
      const { data } = await supabase.from('profiles').select('status').eq('id', userId).single();
      const newStatus = data?.status === 'active' ? 'suspended' : 'active';

      const { error } = await supabase.from('profiles').update({ status: newStatus }).eq('id', userId);
      if (error) throw error;
  };

  const updateSystemConfig = async (config: SystemConfig) => {
      await dbService.updateSystemConfig(config);
      setSystemConfig(config);
  };

  const changePassword = async (password: string) => {
      const { error } = await supabase.auth.updateUser({ password });
      if (error) throw error;
  };

  return (
    <AuthContext.Provider value={{ 
        user, 
        systemConfig,
        login, 
        signup, 
        logout, 
        loading,
        getAllUsers,
        toggleUserStatus,
        updateSystemConfig,
        changePassword
    }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import React, { useState, useEffect } from 'react';
import { BillUploader } from './components/BillUploader';
import { Dashboard } from './components/Dashboard';
import { InsightPanel } from './components/InsightPanel';
import { ReminderModal } from './components/ReminderModal';
import { Settings } from './components/Settings';
import { LandingPage } from './components/LandingPage';
import { AdminPanel } from './components/AdminPanel';
import { Bill } from './types';
import { LayoutDashboard, PieChart, Bell, Settings as SettingsIcon, Menu, Shield, LogOut, LockKeyhole } from 'lucide-react';
import { useAuth } from './contexts/AuthContext';
import { dbService } from './services/dbService';

const App: React.FC = () => {
  const { user, logout, loading: authLoading } = useAuth();
  const [bills, setBills] = useState<Bill[]>([]);
  const [dataLoading, setDataLoading] = useState(false);
  const [view, setView] = useState<'dashboard' | 'upload' | 'settings' | 'admin'>('dashboard');
  const [showReminder, setShowReminder] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Load data from DB when user logs in
  useEffect(() => {
    if (user) {
      setDataLoading(true);
      dbService.getBills(user.id)
        .then(setBills)
        .catch(console.error)
        .finally(() => setDataLoading(false));
    } else {
        setBills([]);
    }
  }, [user]);

  const refreshBills = async () => {
      if (user) {
          const freshBills = await dbService.getBills(user.id);
          setBills(freshBills);
      }
  };

  const handleBillsProcessed = async (newBills: Bill[]) => {
    // Add locally for instant UI feedback, but refresh to ensure sync
    await refreshBills();
    setView('dashboard');
  };

  const handleUpdateBill = async (updatedBill: Bill) => {
    // Optimistic update
    setBills(prev => prev.map(b => b.id === updatedBill.id ? updatedBill : b));

    try {
        await dbService.updateBill(updatedBill);
    } catch (error) {
        console.error("Failed to sync update", error);
        // Revert on error would go here
    }
  };

  const handleAddBill = async (newBill: Bill) => {
    if (!user) return;
    try {
        await dbService.createBill(newBill, user.id);
        await refreshBills();
    } catch (error) {
        console.error("Failed to create manual bill", error);
    }
  };

  if (authLoading) {
    return <div className="min-h-screen flex items-center justify-center bg-gray-50"><div className="animate-pulse text-indigo-600">Loading MileMaster...</div></div>;
  }

  // If not logged in, show the new Landing/Auth Page
  if (!user) {
    return <LandingPage />;
  }

  return (
    <div className="min-h-screen bg-gray-50 font-sans">
      {/* Mobile Header */}
      <div className="lg:hidden bg-white border-b border-gray-200 p-4 flex justify-between items-center sticky top-0 z-20">
         <div className="flex items-center gap-2 text-indigo-600 font-bold text-xl">
             <Shield className="w-6 h-6" />
             MileMaster
         </div>
         <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}>
             <Menu className="w-6 h-6 text-gray-600" />
         </button>
      </div>

      <div className="flex">
        {/* Sidebar */}
        <aside className={`
            fixed lg:sticky top-0 left-0 h-screen w-64 bg-white border-r border-gray-200 z-30 transition-transform transform lg:transform-none
            ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}
        `}>
            <div className="p-6 flex flex-col border-b border-gray-100">
                <div className="flex items-center gap-2 text-indigo-600 font-bold text-2xl mb-1">
                    <Shield className="w-8 h-8" />
                    MileMaster
                </div>
                <span className="text-xs text-gray-400 ml-10">v2.0 (Cloud)</span>
            </div>

            <div className="px-6 py-4">
              <div className="flex items-center gap-3 p-3 bg-indigo-50/50 rounded-xl border border-indigo-50">
                <div className="w-8 h-8 rounded-full bg-indigo-200 flex items-center justify-center text-indigo-700 font-bold">
                  {user.name.charAt(0).toUpperCase()}
                </div>
                <div className="overflow-hidden">
                  <p className="text-sm font-semibold text-gray-900 truncate">{user.name}</p>
                  <div className="flex items-center gap-1">
                      <p className="text-xs text-gray-500 truncate">{user.email}</p>
                      {user.role === 'admin' && <span className="text-[10px] bg-indigo-100 text-indigo-700 px-1 rounded">ADMIN</span>}
                  </div>
                </div>
              </div>
            </div>

            <nav className="p-4 space-y-2">
                <button 
                    onClick={() => { setView('dashboard'); setIsMobileMenuOpen(false); }}
                    className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-colors ${view === 'dashboard' ? 'bg-indigo-50 text-indigo-600' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                    <LayoutDashboard className="w-5 h-5" />
                    Dashboard
                </button>
                <button 
                    onClick={() => { setView('upload'); setIsMobileMenuOpen(false); }}
                    className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-colors ${view === 'upload' ? 'bg-indigo-50 text-indigo-600' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                    <PieChart className="w-5 h-5" />
                    Upload & Analyze
                </button>

                {user.role === 'admin' && (
                    <button 
                        onClick={() => { setView('admin'); setIsMobileMenuOpen(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-colors ${view === 'admin' ? 'bg-indigo-50 text-indigo-600' : 'text-gray-600 hover:bg-gray-50'}`}
                    >
                        <LockKeyhole className="w-5 h-5" />
                        Admin Portal
                    </button>
                )}

                <div className="pt-8 mt-8 border-t border-gray-100">
                    <button 
                        onClick={() => { setShowReminder(true); setIsMobileMenuOpen(false); }}
                        className="w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium text-gray-600 hover:bg-gray-50"
                    >
                        <Bell className="w-5 h-5" />
                        Generate Reminder
                    </button>
                    <button 
                        onClick={() => { setView('settings'); setIsMobileMenuOpen(false); }}
                        className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-colors ${view === 'settings' ? 'bg-indigo-50 text-indigo-600' : 'text-gray-600 hover:bg-gray-50'}`}
                    >
                        <SettingsIcon className="w-5 h-5" />
                        Settings
                    </button>
                    <button 
                        onClick={logout}
                        className="w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium text-red-500 hover:bg-red-50 mt-2"
                    >
                        <LogOut className="w-5 h-5" />
                        Sign Out
                    </button>
                </div>
            </nav>
        </aside>

        {/* Main Content */}
        <main className="flex-1 p-4 lg:p-8 max-w-7xl mx-auto w-full">
            {view === 'dashboard' && (
                <div className="space-y-8 animate-fade-in">
                    <header className="flex justify-between items-center">
                        <div>
                            <h1 className="text-2xl font-bold text-gray-900">Financial Overview</h1>
                            <p className="text-gray-500">Welcome back, {user.name}. Here is your summary.</p>
                        </div>
                        <button 
                            onClick={() => setView('upload')}
                            className="hidden md:block bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition shadow-sm font-medium"
                        >
                            + Upload Bill
                        </button>
                    </header>

                    {dataLoading && bills.length === 0 ? (
                        <div className="h-40 flex items-center justify-center text-gray-400">Loading your data...</div>
                    ) : (
                        <>
                            <InsightPanel bills={bills} />
                            <Dashboard 
                                bills={bills} 
                                onUpdateBill={handleUpdateBill}
                                onAddBill={handleAddBill}
                            />
                        </>
                    )}
                </div>
            )}

            {view === 'upload' && (
                <div className="max-w-2xl mx-auto space-y-6 animate-fade-in">
                     <header>
                        <button 
                            onClick={() => setView('dashboard')}
                            className="text-sm text-gray-500 hover:text-gray-900 mb-2 block"
                        >
                            &larr; Back to Dashboard
                        </button>
                        <h1 className="text-2xl font-bold text-gray-900">Upload Statement</h1>
                        <p className="text-gray-500">Upload a screenshot or PDF of your bill. AI will extract the details.</p>
                    </header>
                    <BillUploader onBillProcessed={handleBillsProcessed} />
                </div>
            )}

            {view === 'settings' && (
                <Settings />
            )}

            {view === 'admin' && user.role === 'admin' && (
                <AdminPanel />
            )}
        </main>
      </div>

      <ReminderModal 
        bills={bills} 
        isOpen={showReminder} 
        onClose={() => setShowReminder(false)} 
      />
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { extractBillData } from '../services/geminiService';
import { dbService } from '../services/dbService';
import { Bill } from '../types';
import { Loader2, Upload, AlertCircle, FileText, CheckCircle } from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';

interface BillUploaderProps {
  onBillProcessed: (bills: Bill[]) => void;
}

export const BillUploader: React.FC<BillUploaderProps> = ({ onBillProcessed }) => {
  const { user } = useAuth();
  const [isLoading, setIsLoading] = useState(false);
  const [uploadStatus, setUploadStatus] = useState<string | null>(null);
  const [errors, setErrors] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const processFile = async (file: File): Promise<Bill[]> => {
     if (!user) throw new Error("User not authenticated");

     return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = async () => {
            try {
                // 1. AI Parsing (Client Side)
                const base64String = (reader.result as string).split(',')[1];
                const extractedData = await extractBillData(base64String, file.type);

                if (!extractedData.bills || extractedData.bills.length === 0) {
                     reject(new Error(`No bills found in ${file.name}`));
                     return;
                }

                const createdBills: Bill[] = [];

                // 2. Save to Supabase
                for (const billData of extractedData.bills) {
                    const tempBill: Bill = {
                        id: 'temp', // DB assigns ID
                        bankName: billData.bankName || "Unknown Bank",
                        cardName: billData.cardName || "Unknown Card",
                        statementDate: billData.statementDate || new Date().toISOString().split('T')[0],
                        dueDate: billData.dueDate || new Date().toISOString().split('T')[0],
                        totalAmount: billData.totalAmount,
                        isPaid: false,
                        uploadedAt: new Date().toISOString(),
                        riskScore: 0,
                        transactions: (billData.transactions || []).map((t) => ({
                            id: 'temp',
                            date: t.date,
                            description: t.description,
                            amount: t.amount,
                            category: t.category,
                            suggestedCard: "Analyzing...",
                        }))
                    };

                    const savedBill = await dbService.createBill(tempBill, user.id, file);
                    createdBills.push(savedBill);
                }

                resolve(createdBills);
            } catch (err: any) {
                reject(new Error(`Failed to parse ${file.name}: ${err.message || "AI extraction failed"}`));
            }
        };
        reader.onerror = () => reject(new Error(`Error reading file: ${file.name}`));
        reader.readAsDataURL(file);
     });
  }

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setIsLoading(true);
    setErrors([]);
    setUploadStatus(`Preparing to process ${files.length} file(s)...`);

    const allNewBills: Bill[] = [];
    const newErrors: string[] = [];
    const fileArray: File[] = Array.from(files);

    try {
        const results = await Promise.allSettled(fileArray.map(file => processFile(file)));

        results.forEach((result, index) => {
            if (result.status === 'fulfilled') {
                allNewBills.push(...result.value);
            } else {
                newErrors.push((result.reason as any)?.message || "Unknown error occurred");
            }
        });

        if (allNewBills.length > 0) {
            onBillProcessed(allNewBills);
            const successMsg = `Successfully processed ${allNewBills.length} bills from ${fileArray.length - newErrors.length} valid files.`;
            setUploadStatus(successMsg);
        } else {
            setUploadStatus(null);
        }

        if (newErrors.length > 0) {
            setErrors(newErrors);
        }
    } catch (err) {
        setErrors(["An unexpected error occurred during processing."]);
    } finally {
        setIsLoading(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
      <h2 className="text-lg font-semibold text-gray-900 mb-4 flex items-center gap-2">
        <Upload className="w-5 h-5 text-primary" />
        Upload Bills
      </h2>

      <div 
        className={`border-2 border-dashed rounded-xl p-12 text-center transition-colors ${
          isLoading ? 'border-primary bg-indigo-50' : 'border-gray-300 hover:border-primary hover:bg-gray-50'
        }`}
        onClick={() => !isLoading && fileInputRef.current?.click()}
      >
        {isLoading ? (
          <div className="flex flex-col items-center gap-3">
            <Loader2 className="w-8 h-8 text-primary animate-spin" />
            <p className="text-sm text-gray-600 font-medium">
                {uploadStatus || "AI is analyzing & saving to cloud..."}
            </p>
            <p className="text-xs text-gray-400">Extracting data from multiple files...</p>
          </div>
        ) : (
          <div className="flex flex-col items-center gap-3 cursor-pointer">
            <div className="bg-indigo-100 p-4 rounded-full">
               <FileText className="w-8 h-8 text-primary" />
            </div>
            <p className="text-sm text-gray-600 font-medium">Click to upload PDF or Images</p>
            <p className="text-xs text-gray-400">Select one or multiple files to process at once</p>
          </div>
        )}
        <input 
            type="file" 
            multiple
            ref={fileInputRef} 
            onChange={handleFileUpload} 
            className="hidden" 
            accept="image/*,.pdf"
        />
      </div>

      {!isLoading && uploadStatus && (
          <div className="mt-4 p-3 bg-green-50 text-green-700 text-sm rounded-lg flex items-center gap-2">
            <CheckCircle className="w-4 h-4 shrink-0" />
            {uploadStatus}
          </div>
      )}

      {errors.length > 0 && (
        <div className="mt-4 p-3 bg-red-50 text-red-700 text-sm rounded-lg">
            <div className="flex items-center gap-2 font-medium mb-2">
                <AlertCircle className="w-4 h-4" />
                Errors encountered:
            </div>
            <ul className="list-disc list-inside space-y-1">
                {errors.map((err, i) => (
                    <li key={i} className="text-xs opacity-90">{err}</li>
                ))}
            </ul>
        </div>
      )}
    </div>
  );
};

