  onAddBill: (bill: Bill) => void;
}

const COLORS = ['#4F46E5', '#10B981', '#F59E0B', '#EF4444', '#8B5CF6'];
const BANK_COLORS: Record<string, string> = {
    'DBS': '#ef4444', // Red
    'Citibank': '#0ea5e9', // Blue
    'UOB': '#0f172a', // Dark Navy
    'HSBC': '#db2777', // Pink
    'OCBC': '#ef4444', // Red
    'Standard Chartered': '#16a34a', // Green
    'AMEX': '#2563eb', // Blue
    'Unknown': '#9ca3af' // Gray
};
const DEFAULT_BANK_COLORS = ['#6366f1', '#8b5cf6', '#d946ef', '#f43f5e', '#f97316'];

export const Dashboard: React.FC<DashboardProps> = ({ bills, onUpdateBill, onAddBill }) => {
  const [selectedBillForPayment, setSelectedBillForPayment] = useState<Bill | null>(null);
  const [billToEdit, setBillToEdit] = useState<Bill | null>(null);
  const [isManualModalOpen, setIsManualModalOpen] = useState(false);
  const [selectedMonthFilter, setSelectedMonthFilter] = useState<string>('ALL');

  const totalDue = useMemo(() => 
    bills.filter(b => !b.isPaid).reduce((acc, b) => acc + b.totalAmount, 0), 
  [bills]);

  const categoryData = useMemo(() => {
    const categories: Record<string, number> = {};
    bills.forEach(bill => {
      bill.transactions.forEach(t => {
        categories[t.category] = (categories[t.category] || 0) + t.amount;
      });
    });
    return Object.keys(categories).map(key => ({ name: key, value: categories[key] }));
  }, [bills]);

  // ------------------------------------------------------------------
  // Logic for Clustered Bar Chart (Spend Trend by Bank per Month)
  // ------------------------------------------------------------------
  const { clusteredData, uniqueBanks } = useMemo(() => {
    const monthlyData: Record<string, Record<string, number>> = {};
    const banksSet = new Set<string>();

    bills.forEach(bill => {
        // Use Statement Date for spend allocation, fallback to Due Date
        const dateStr = bill.statementDate || bill.dueDate;
        const dateObj = new Date(dateStr);

        // Key format: YYYY-MM for sorting/grouping
        const monthKey = `${dateObj.getFullYear()}-${String(dateObj.getMonth() + 1).padStart(2, '0')}`;
        // Display label: MMM YYYY
        const monthLabel = dateObj.toLocaleDateString('en-GB', { month: 'short', year: 'numeric' });

        if (!monthlyData[monthKey]) {
            monthlyData[monthKey] = { name: monthLabel, _sortKey: monthKey } as any;
        }

        // Normalize Bank Name (simple cleaning)
        let bankName = bill.bankName.trim();
        if (bankName.toLowerCase().includes('dbs')) bankName = 'DBS';
        else if (bankName.toLowerCase().includes('uob')) bankName = 'UOB';
        else if (bankName.toLowerCase().includes('citi')) bankName = 'Citibank';
        else if (bankName.toLowerCase().includes('hsbc')) bankName = 'HSBC';
        else if (bankName.toLowerCase().includes('ocbc')) bankName = 'OCBC';
        else if (bankName.toLowerCase().includes('american express') || bankName.toLowerCase().includes('amex')) bankName = 'AMEX';

        banksSet.add(bankName);

        // Add amount
        const currentAmount = (monthlyData[monthKey][bankName] as number) || 0;
        monthlyData[monthKey][bankName] = currentAmount + bill.totalAmount;
    });

    // Convert to array and sort by date
    const dataArray = Object.values(monthlyData).sort((a: any, b: any) => 
        a._sortKey.localeCompare(b._sortKey)
    );

    return { clusteredData: dataArray, uniqueBanks: Array.from(banksSet) };
  }, [bills]);

  const upcomingBills = bills
    .filter(b => !b.isPaid)
    .sort((a, b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime());

  // Extract unique months from bills for filtering list
  const availableMonths = useMemo(() => {
    const months = new Set<string>();
    bills.forEach(bill => {
      if (bill.dueDate) {
        const date = new Date(bill.dueDate);
        const key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
        months.add(key);
      }
    });
    return Array.from(months).sort().reverse(); // Newest first
  }, [bills]);

  const filteredBills = useMemo(() => {
    if (selectedMonthFilter === 'ALL') return bills;
    return bills.filter(b => b.dueDate.startsWith(selectedMonthFilter));
  }, [bills, selectedMonthFilter]);

  const handlePaymentConfirm = (billId: string, details: PaymentDetails) => {
    const billToUpdate = bills.find(b => b.id === billId);
    if (billToUpdate) {
        onUpdateBill({
            ...billToUpdate,
            isPaid: true,
            paymentDetails: details
        });
    }
  };

  const handleEditSave = (updatedBill: Bill) => {
      onUpdateBill(updatedBill);
  };

  const formatDateForDisplay = (dateStr: string) => {
     const date = new Date(dateStr);
     return date.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });
  };

  const getMonthLabel = (yyyyMm: string) => {
    const [year, month] = yyyyMm.split('-');
    const date = new Date(parseInt(year), parseInt(month) - 1, 1);
    return date.toLocaleDateString('en-GB', { month: 'short', year: 'numeric' }).toUpperCase();
  };

  const handleViewDocument = async (bill: Bill) => {
      if (!bill.filePath) return;
      const url = await dbService.getBillFileUrl(bill.filePath);
      if (url) {
          window.open(url, '_blank');
      } else {
          alert("Could not retrieve document. It may have been deleted.");
      }
  };

  return (
    <div className="space-y-6">
      {/* KPIs */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm text-gray-500">Total Outstanding</p>
              <h3 className="text-2xl font-bold text-gray-900">${totalDue.toFixed(2)}</h3>
            </div>
            <div className="bg-red-100 p-2 rounded-lg">
              <AlertTriangle className="w-5 h-5 text-red-600" />
            </div>
          </div>
        </div>

        <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm text-gray-500">Bills Due Soon</p>
              <h3 className="text-2xl font-bold text-gray-900">{upcomingBills.length}</h3>
            </div>
            <div className="bg-yellow-100 p-2 rounded-lg">
              <Clock className="w-5 h-5 text-yellow-600" />
            </div>
          </div>
        </div>

        <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
           <div className="flex justify-between items-start">
            <div>
              <p className="text-sm text-gray-500">Processed Bills</p>
              <h3 className="text-2xl font-bold text-gray-900">{bills.length}</h3>
            </div>
             <div className="bg-green-100 p-2 rounded-lg">
              <CheckCircle className="w-5 h-5 text-green-600" />
            </div>
          </div>
        </div>
      </div>

      {/* Charts Row */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

        {/* Upcoming List */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 h-80 overflow-y-auto">
          <h3 className="text-lg font-semibold mb-4">Upcoming Deadlines</h3>
          {upcomingBills.length === 0 ? (
            <p className="text-gray-400 text-center mt-10">No upcoming bills. Great job!</p>
          ) : (
            <div className="space-y-3">
              {upcomingBills.map(bill => (
                <div key={bill.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg border border-gray-100 hover:border-primary/30 transition-colors">
                  <div>
                    <p className="font-medium text-gray-800">{bill.bankName} - {bill.cardName}</p>
                    <p className="text-xs text-gray-500">Due: {bill.dueDate}</p>
                  </div>
                  <div className="text-right">
                    <p className="font-bold text-gray-900">${bill.totalAmount.toFixed(2)}</p>
                    <span className="text-xs text-red-500 font-medium bg-red-50 px-2 py-1 rounded-full">Unpaid</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Spend Breakdown Pie Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 h-80">
          <h3 className="text-lg font-semibold mb-4">Spend by Category</h3>
          {categoryData.length > 0 ? (
             <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={categoryData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  fill="#8884d8"
                  paddingAngle={5}
                  dataKey="value"
                >
                  {categoryData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip formatter={(value: number) => `$${value.toFixed(2)}`} />
              </PieChart>
            </ResponsiveContainer>
          ) : (
             <div className="flex items-center justify-center h-full text-gray-400">No Data Available</div>
          )}
        </div>
      </div>

      {/* Bank Spend Trend (Clustered Bar Chart) */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <div className="flex items-center justify-between mb-6">
              <h3 className="text-lg font-semibold text-gray-900 flex items-center gap-2">
                  <TrendingUp className="w-5 h-5 text-indigo-600" />
                  Spend Trend by Bank
              </h3>
          </div>
          <div className="h-80">
            {clusteredData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                    <BarChart 
                        data={clusteredData} 
                        margin={{ top: 20, right: 30, left: 20, bottom: 5 }}
                    >
                        <CartesianGrid strokeDasharray="3 3" vertical={false} />
                        <XAxis dataKey="name" tick={{fontSize: 12}} axisLine={false} tickLine={false} />
                        <YAxis tick={{fontSize: 12}} axisLine={false} tickLine={false} prefix="$" />
                        <Tooltip 
                            formatter={(value: number, name: string) => [`$${value.toLocaleString()}`, name]}
                            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                            cursor={{ fill: '#f3f4f6' }}
                        />
                        <Legend />

                        {uniqueBanks.map((bank, index) => (
                            <Bar 
                                key={bank} 
                                dataKey={bank} 
                                fill={BANK_COLORS[bank] || DEFAULT_BANK_COLORS[index % DEFAULT_BANK_COLORS.length]} 
                                radius={[4, 4, 0, 0]} 
                            />
                        ))}
                    </BarChart>
                </ResponsiveContainer>
            ) : (
                <div className="flex items-center justify-center h-full text-gray-400 text-sm">
                    Add bills to see your monthly bank spending comparison.
                </div>
            )}
          </div>
      </div>

      {/* Bills Table */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
          {/* Table Header with Filters */}
          <div className="p-6 border-b border-gray-100 flex flex-col md:flex-row md:items-center justify-between gap-4">
              <div className="flex items-center gap-4">
                  <h3 className="text-lg font-semibold text-gray-900">Recent Bills</h3>

                  {/* Month Filters */}
                  {availableMonths.length > 0 && (
                    <div className="flex items-center bg-gray-100 p-1 rounded-lg overflow-x-auto">
                        <button
                            onClick={() => setSelectedMonthFilter('ALL')}
                            className={`px-3 py-1 text-xs font-medium rounded-md transition-all whitespace-nowrap ${
                                selectedMonthFilter === 'ALL' 
                                ? 'bg-white text-indigo-600 shadow-sm' 
                                : 'text-gray-500 hover:text-gray-700'
                            }`}
                        >
                            ALL
                        </button>
                        {availableMonths.map(month => (
                            <button
                                key={month}
                                onClick={() => setSelectedMonthFilter(month)}
                                className={`px-3 py-1 text-xs font-medium rounded-md transition-all whitespace-nowrap ${
                                    selectedMonthFilter === month 
                                    ? 'bg-white text-indigo-600 shadow-sm' 
                                    : 'text-gray-500 hover:text-gray-700'
                                }`}
                            >
                                {getMonthLabel(month)}
                            </button>
                        ))}
                    </div>
                  )}
              </div>

              <button 
                onClick={() => setIsManualModalOpen(true)}
                className="flex items-center gap-2 text-sm bg-indigo-50 text-indigo-600 px-3 py-2 rounded-lg hover:bg-indigo-100 font-medium transition-colors whitespace-nowrap"
              >
                <Plus className="w-4 h-4" />
                Add Manual Bill
              </button>
          </div>

          <div className="overflow-x-auto">
              <table className="w-full text-left text-sm text-gray-600">
                  <thead className="bg-gray-50 text-xs uppercase font-semibold text-gray-500">
                      <tr>
                          <th className="px-6 py-4">Bank / Card</th>
                          <th className="px-6 py-4">Due Date</th>
                          <th className="px-6 py-4">Amount</th>
                          <th className="px-6 py-4">Status</th>
                          <th className="px-6 py-4">Payment Info</th>
                          <th className="px-6 py-4">Actions</th>
                      </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                      {filteredBills.length === 0 ? (
                          <tr>
                              <td colSpan={6} className="px-6 py-8 text-center text-gray-400">No bills found for this period.</td>
                          </tr>
                      ) : (
                          filteredBills.map(bill => (
                              <tr key={bill.id} className="hover:bg-gray-50 transition-colors">
                                  <td className="px-6 py-4">
                                      <div className="font-medium text-gray-900">{bill.cardName}</div>
                                      <div className="text-xs text-gray-400">{bill.bankName}</div>
                                  </td>
                                  <td className="px-6 py-4">{formatDateForDisplay(bill.dueDate)}</td>
                                  <td className="px-6 py-4 font-medium">${bill.totalAmount.toFixed(2)}</td>
                                  <td className="px-6 py-4">
                                      <span className={`px-3 py-1 rounded-full text-xs font-medium ${
                                          bill.isPaid 
                                          ? 'bg-green-100 text-green-700' 
                                          : 'bg-amber-100 text-amber-700'
                                      }`}>
                                          {bill.isPaid ? 'Paid' : 'Pending'}
                                      </span>
                                  </td>
                                  <td className="px-6 py-4 text-xs">
                                      {bill.isPaid && bill.paymentDetails ? (
                                          <div>
                                              <p><span className="font-semibold text-gray-700">{bill.paymentDetails.method}</span></p>
                                              <p className="text-gray-400">Ref: {bill.paymentDetails.transactionId}</p>
                                          </div>
                                      ) : (
                                          <span className="text-gray-300">-</span>
                                      )}
                                  </td>
                                  <td className="px-6 py-4">
                                      <div className="flex items-center gap-2">
                                          {bill.filePath && (
                                              <button 
                                                  onClick={() => handleViewDocument(bill)}
                                                  className="p-2 text-indigo-500 hover:text-indigo-700 hover:bg-indigo-50 rounded-full transition-colors"
                                                  title="View Uploaded Document"
                                              >
                                                  <FileText className="w-4 h-4" />
                                              </button>
                                          )}

                                          {!bill.isPaid ? (
                                              <button 
                                                  onClick={() => setSelectedBillForPayment(bill)}
                                                  className="text-indigo-600 hover:text-indigo-800 font-medium text-xs bg-indigo-50 px-3 py-1 rounded-md hover:bg-indigo-100 transition-colors"
                                              >
                                                  Mark Paid
                                              </button>
                                          ) : (
                                            <div className="flex flex-col items-start">
                                                <button 
                                                    disabled
                                                    className="text-gray-400 font-medium text-xs cursor-not-allowed bg-gray-100 px-3 py-1 rounded-md"
                                                >
                                                    Settled
                                                </button>
                                                {/* Display Date Below Button */}
                                                {bill.paymentDetails?.paidAt && (
                                                    <span className="text-[10px] text-gray-500 mt-1 ml-1">
                                                        {formatDateForDisplay(bill.paymentDetails.paidAt)}
                                                    </span>
                                                )}
                                            </div>
                                          )}

                                          <button 
                                            onClick={() => setBillToEdit(bill)}
                                            className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                                            title="Edit Bill Details"
                                          >
                                              <Pencil className="w-4 h-4" />
                                          </button>
                                      </div>
                                  </td>
                              </tr>
                          ))
                      )}
                  </tbody>
              </table>
          </div>
      </div>

      <PaymentModal 
        bill={selectedBillForPayment}
        isOpen={!!selectedBillForPayment}
        onClose={() => setSelectedBillForPayment(null)}
        onConfirm={handlePaymentConfirm}
      />

      <ManualBillModal 
        isOpen={isManualModalOpen}
        onClose={() => setIsManualModalOpen(false)}
        onAdd={onAddBill}
      />

      <EditBillModal 
        bill={billToEdit}
        isOpen={!!billToEdit}
        onClose={() => setBillToEdit(null)}
        onSave={handleEditSave}
      />
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { extractBillData } from '../services/geminiService';
import { dbService } from '../services/dbService';
import { Bill } from '../types';
import { Loader2, Upload, AlertCircle, FileText, CheckCircle } from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';

interface BillUploaderProps {
  onBillProcessed: (bills: Bill[]) => void;
}

export const BillUploader: React.FC<BillUploaderProps> = ({ onBillProcessed }) => {
  const { user } = useAuth();
  const [isLoading, setIsLoading] = useState(false);
  const [uploadStatus, setUploadStatus] = useState<string | null>(null);
  const [errors, setErrors] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Helper to prevent infinite hanging
  const uploadWithTimeout = async (promise: Promise<any>, ms: number = 30000) => {
    let timeoutId;
    const timeoutPromise = new Promise((_, reject) => {
      timeoutId = setTimeout(() => reject(new Error("Upload timed out (30s). Check your internet or Supabase connection.")), ms);
    });
    return Promise.race([
      promise,
      timeoutPromise
    ]).then((res) => {
      clearTimeout(timeoutId);
      return res;
    });
  };

  const processFile = async (file: File): Promise<Bill[]> => {
     if (!user) throw new Error("User not authenticated");

     // File Size Check (5MB Limit)
     if (file.size > 5 * 1024 * 1024) {
         throw new Error(`File ${file.name} exceeds 5MB limit.`);
     }

     return new Promise(async (resolve, reject) => {
        const reader = new FileReader();

        reader.onload = async () => {
            try {
                const base64String = (reader.result as string).split(',')[1];

                // --- PARALLEL EXECUTION START ---
                // Start uploading to Storage and analyzing with AI at the same time
                // We add a timeout to the upload part so it doesn't freeze the app forever if Supabase is blocked
                const [uploadResult, aiResult] = await Promise.allSettled([
                    uploadWithTimeout(dbService.uploadBillDocument(file, user.id)),
                    extractBillData(base64String, file.type)
                ]);

                // 1. Handle AI Result
                if (aiResult.status === 'rejected') {
                    throw new Error(aiResult.reason?.message || "AI extraction failed");
                }
                const extractedData = aiResult.value;

                if (!extractedData.bills || extractedData.bills.length === 0) {
                     throw new Error(`No bills found in ${file.name}`);
                }

                // 2. Handle Upload Result
                let uploadedFilePath: string | undefined = undefined;
                if (uploadResult.status === 'fulfilled') {
                    uploadedFilePath = uploadResult.value as string;
                } else {
                    console.warn(`File upload failed for ${file.name}:`, uploadResult.reason);
                    // We don't throw here, we allow the bill to be created even if the PDF upload failed
                }
                // --- PARALLEL EXECUTION END ---

                const createdBills: Bill[] = [];

                // 3. Save Bills to DB (Using the single uploaded file path)
                for (const billData of extractedData.bills) {
                    const tempBill: Bill = {
                        id: 'temp', // DB assigns ID
                        bankName: billData.bankName || "Unknown Bank",
                        cardName: billData.cardName || "Unknown Card",
                        statementDate: billData.statementDate || new Date().toISOString().split('T')[0],
                        dueDate: billData.dueDate || new Date().toISOString().split('T')[0],
                        totalAmount: billData.totalAmount,
                        isPaid: false,
                        uploadedAt: new Date().toISOString(),
                        riskScore: 0,
                        transactions: (billData.transactions || []).map((t) => ({
                            id: 'temp',
                            date: t.date,
                            description: t.description,
                            amount: t.amount,
                            category: t.category,
                            suggestedCard: "Analyzing...",
                        }))
                    };

                    // Pass the already uploaded path
                    const savedBill = await dbService.createBill(tempBill, user.id, uploadedFilePath);
                    createdBills.push(savedBill);
                }

                resolve(createdBills);
            } catch (err: any) {
                reject(new Error(`Failed to parse ${file.name}: ${err.message || "Unknown error"}`));
            }
        };

        reader.onerror = () => reject(new Error(`Error reading file: ${file.name}`));
        reader.readAsDataURL(file);
     });
  }

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setIsLoading(true);
    setErrors([]);
    setUploadStatus(`Preparing to process ${files.length} file(s)...`);

    const allNewBills: Bill[] = [];
    const newErrors: string[] = [];
    const fileArray: File[] = Array.from(files);

    try {
        // Run all file processes in parallel
        const results = await Promise.allSettled(fileArray.map(file => processFile(file)));

        results.forEach((result, index) => {
            if (result.status === 'fulfilled') {
                allNewBills.push(...result.value);
            } else {
                newErrors.push((result.reason as any)?.message || "Unknown error occurred");
            }
        });

        if (allNewBills.length > 0) {
            onBillProcessed(allNewBills);
            const successMsg = `Successfully processed ${allNewBills.length} bills from ${fileArray.length - newErrors.length} valid files.`;
            setUploadStatus(successMsg);
        } else {
            setUploadStatus(null);
        }

        if (newErrors.length > 0) {
            setErrors(newErrors);
        }
    } catch (err) {
        setErrors(["An unexpected error occurred during processing."]);
    } finally {
        setIsLoading(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
      <h2 className="text-lg font-semibold text-gray-900 mb-4 flex items-center gap-2">
        <Upload className="w-5 h-5 text-primary" />
        Upload Bills
      </h2>

      <div 
        className={`border-2 border-dashed rounded-xl p-12 text-center transition-colors ${
          isLoading ? 'border-primary bg-indigo-50' : 'border-gray-300 hover:border-primary hover:bg-gray-50'
        }`}
        onClick={() => !isLoading && fileInputRef.current?.click()}
      >
        {isLoading ? (
          <div className="flex flex-col items-center gap-3">
            <Loader2 className="w-8 h-8 text-primary animate-spin" />
            <p className="text-sm text-gray-600 font-medium">
                {uploadStatus || "AI is analyzing & saving to cloud..."}
            </p>
            <p className="text-xs text-gray-400">Please wait while we extract the data.</p>
          </div>
        ) : (
          <div className="flex flex-col items-center gap-3 cursor-pointer">
            <div className="bg-indigo-100 p-4 rounded-full">
               <FileText className="w-8 h-8 text-primary" />
            </div>
            <p className="text-sm text-gray-600 font-medium">Click to upload PDF or Images</p>
            <p className="text-xs text-gray-400">Supports PDF, JPG, PNG (Max 5MB)</p>
          </div>
        )}
        <input 
            type="file" 
            multiple
            ref={fileInputRef} 
            onChange={handleFileUpload} 
            className="hidden" 
            accept="image/*,.pdf"
        />
      </div>

      {!isLoading && uploadStatus && (
          <div className="mt-4 p-3 bg-green-50 text-green-700 text-sm rounded-lg flex items-center gap-2">
            <CheckCircle className="w-4 h-4 shrink-0" />
            {uploadStatus}
          </div>
      )}

      {errors.length > 0 && (
        <div className="mt-4 p-3 bg-red-50 text-red-700 text-sm rounded-lg">
            <div className="flex items-center gap-2 font-medium mb-2">
                <AlertCircle className="w-4 h-4" />
                Errors encountered:
            </div>
            <ul className="list-disc list-inside space-y-1">
                {errors.map((err, i) => (
                    <li key={i} className="text-xs opacity-90">{err}</li>
                ))}
            </ul>
        </div>
      )}
    </div>
  );
};

import React, { useMemo, useState, useEffect } from 'react';
import { Bill, PaymentDetails } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, BarChart, Bar, XAxis, YAxis, CartesianGrid, Legend } from 'recharts';
import { AlertTriangle, CheckCircle, Clock, Plus, Filter, TrendingUp, Pencil, FileText, ExternalLink } from 'lucide-react';
import { PaymentModal } from './PaymentModal';
import { ManualBillModal } from './ManualBillModal';
import { EditBillModal } from './EditBillModal';
import { dbService } from '../services/dbService';

interface DashboardProps {
  bills: Bill[];
  onUpdateBill: (bill: Bill) => void;
  onAddBill: (bill: Bill) => void;
}

const COLORS = ['#4F46E5', '#10B981', '#F59E0B', '#EF4444', '#8B5CF6'];
const BANK_COLORS: Record<string, string> = {
    'DBS': '#ef4444', // Red
    'Citibank': '#0ea5e9', // Blue
    'UOB': '#0f172a', // Dark Navy
    'HSBC': '#db2777', // Pink
    'OCBC': '#ef4444', // Red
    'Standard Chartered': '#16a34a', // Green
    'AMEX': '#2563eb', // Blue
    'Unknown': '#9ca3af' // Gray
};
const DEFAULT_BANK_COLORS = ['#6366f1', '#8b5cf6', '#d946ef', '#f43f5e', '#f97316'];

export const Dashboard: React.FC<DashboardProps> = ({ bills, onUpdateBill, onAddBill }) => {
  const [selectedBillForPayment, setSelectedBillForPayment] = useState<Bill | null>(null);
  const [billToEdit, setBillToEdit] = useState<Bill | null>(null);
  const [isManualModalOpen, setIsManualModalOpen] = useState(false);
  const [selectedMonthFilter, setSelectedMonthFilter] = useState<string>('ALL');

  const totalDue = useMemo(() => 
    bills.filter(b => !b.isPaid).reduce((acc, b) => acc + b.totalAmount, 0), 
  [bills]);

  const categoryData = useMemo(() => {
    const categories: Record<string, number> = {};
    bills.forEach(bill => {
      bill.transactions.forEach(t => {
        categories[t.category] = (categories[t.category] || 0) + t.amount;
      });
    });
    return Object.keys(categories).map(key => ({ name: key, value: categories[key] }));
  }, [bills]);

  // ------------------------------------------------------------------
  // Logic for Clustered Bar Chart (Spend Trend by Bank per Month)
  // ------------------------------------------------------------------
  const { clusteredData, uniqueBanks } = useMemo(() => {
    const monthlyData: Record<string, Record<string, number>> = {};
    const banksSet = new Set<string>();

    bills.forEach(bill => {
        // Use Statement Date for spend allocation, fallback to Due Date
        const dateStr = bill.statementDate || bill.dueDate;
        const dateObj = new Date(dateStr);

        // Key format: YYYY-MM for sorting/grouping
        const monthKey = `${dateObj.getFullYear()}-${String(dateObj.getMonth() + 1).padStart(2, '0')}`;
        // Display label: MMM YYYY
        const monthLabel = dateObj.toLocaleDateString('en-GB', { month: 'short', year: 'numeric' });

        if (!monthlyData[monthKey]) {
            monthlyData[monthKey] = { name: monthLabel, _sortKey: monthKey } as any;
        }

        // Normalize Bank Name (simple cleaning)
        let bankName = bill.bankName.trim();
        if (bankName.toLowerCase().includes('dbs')) bankName = 'DBS';
        else if (bankName.toLowerCase().includes('uob')) bankName = 'UOB';
        else if (bankName.toLowerCase().includes('citi')) bankName = 'Citibank';
        else if (bankName.toLowerCase().includes('hsbc')) bankName = 'HSBC';
        else if (bankName.toLowerCase().includes('ocbc')) bankName = 'OCBC';
        else if (bankName.toLowerCase().includes('american express') || bankName.toLowerCase().includes('amex')) bankName = 'AMEX';

        banksSet.add(bankName);

        // Add amount
        const currentAmount = (monthlyData[monthKey][bankName] as number) || 0;
        monthlyData[monthKey][bankName] = currentAmount + bill.totalAmount;
    });

    // Convert to array and sort by date
    const dataArray = Object.values(monthlyData).sort((a: any, b: any) => 
        a._sortKey.localeCompare(b._sortKey)
    );

    return { clusteredData: dataArray, uniqueBanks: Array.from(banksSet) };
  }, [bills]);

  const upcomingBills = bills
    .filter(b => !b.isPaid)
    .sort((a, b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime());

  // Extract unique months from bills for filtering list
  const availableMonths = useMemo(() => {
    const months = new Set<string>();
    bills.forEach(bill => {
      if (bill.dueDate) {
        const date = new Date(bill.dueDate);
        const key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
        months.add(key);
      }
    });
    return Array.from(months).sort().reverse(); // Newest first
  }, [bills]);

  const filteredBills = useMemo(() => {
    if (selectedMonthFilter === 'ALL') return bills;
    return bills.filter(b => b.dueDate.startsWith(selectedMonthFilter));
  }, [bills, selectedMonthFilter]);

  const handlePaymentConfirm = (billId: string, details: PaymentDetails) => {
    const billToUpdate = bills.find(b => b.id === billId);
    if (billToUpdate) {
        onUpdateBill({
            ...billToUpdate,
            isPaid: true,
            paymentDetails: details
        });
    }
  };

  const handleEditSave = (updatedBill: Bill) => {
      onUpdateBill(updatedBill);
  };

  const formatDateForDisplay = (dateStr: string) => {
     if (!dateStr) return 'N/A';
     const date = new Date(dateStr);
     return date.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });
  };

  const getMonthLabel = (yyyyMm: string) => {
    if (!yyyyMm) return '';
    const [year, month] = yyyyMm.split('-');
    const date = new Date(parseInt(year), parseInt(month) - 1, 1);
    return date.toLocaleDateString('en-GB', { month: 'short', year: 'numeric' }).toUpperCase();
  };

  const handleViewDocument = async (bill: Bill) => {
      if (!bill.filePath) return;
      const url = await dbService.getBillFileUrl(bill.filePath);
      if (url) {
          window.open(url, '_blank');
      } else {
          alert("Could not retrieve document. It may have been deleted.");
      }
  };

  return (
    <div className="space-y-6">
      {/* KPIs */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm text-gray-500">Total Outstanding</p>
              <h3 className="text-2xl font-bold text-gray-900">${totalDue.toFixed(2)}</h3>
            </div>
            <div className="bg-red-100 p-2 rounded-lg">
              <AlertTriangle className="w-5 h-5 text-red-600" />
            </div>
          </div>
        </div>

        <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm text-gray-500">Bills Due Soon</p>
              <h3 className="text-2xl font-bold text-gray-900">{upcomingBills.length}</h3>
            </div>
            <div className="bg-yellow-100 p-2 rounded-lg">
              <Clock className="w-5 h-5 text-yellow-600" />
            </div>
          </div>
        </div>

        <div className="bg-white p-5 rounded-xl shadow-sm border border-gray-100">
           <div className="flex justify-between items-start">
            <div>
              <p className="text-sm text-gray-500">Processed Bills</p>
              <h3 className="text-2xl font-bold text-gray-900">{bills.length}</h3>
            </div>
             <div className="bg-green-100 p-2 rounded-lg">
              <CheckCircle className="w-5 h-5 text-green-600" />
            </div>
          </div>
        </div>
      </div>

      {/* Charts Row */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

        {/* Upcoming List */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 h-80 overflow-y-auto">
          <h3 className="text-lg font-semibold mb-4">Upcoming Deadlines</h3>
          {upcomingBills.length === 0 ? (
            <p className="text-gray-400 text-center mt-10">No upcoming bills. Great job!</p>
          ) : (
            <div className="space-y-3">
              {upcomingBills.map(bill => (
                <div key={bill.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg border border-gray-100 hover:border-primary/30 transition-colors">
                  <div>
                    <p className="font-medium text-gray-800">{bill.bankName} - {bill.cardName}</p>
                    <p className="text-xs text-gray-500">Due: {bill.dueDate}</p>
                  </div>
                  <div className="text-right">
                    <p className="font-bold text-gray-900">${bill.totalAmount.toFixed(2)}</p>
                    <span className="text-xs text-red-500 font-medium bg-red-50 px-2 py-1 rounded-full">Unpaid</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Spend Breakdown Pie Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 h-80">
          <h3 className="text-lg font-semibold mb-4">Spend by Category</h3>
          {categoryData.length > 0 ? (
             <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={categoryData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  fill="#8884d8"
                  paddingAngle={5}
                  dataKey="value"
                >
                  {categoryData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip formatter={(value: number) => `$${value.toFixed(2)}`} />
              </PieChart>
            </ResponsiveContainer>
          ) : (
             <div className="flex items-center justify-center h-full text-gray-400">No Data Available</div>
          )}
        </div>
      </div>

      {/* Bank Spend Trend (Clustered Bar Chart) */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <div className="flex items-center justify-between mb-6">
              <h3 className="text-lg font-semibold text-gray-900 flex items-center gap-2">
                  <TrendingUp className="w-5 h-5 text-indigo-600" />
                  Spend Trend by Bank
              </h3>
          </div>
          <div className="h-80">
            {clusteredData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                    <BarChart 
                        data={clusteredData} 
                        margin={{ top: 20, right: 30, left: 20, bottom: 5 }}
                    >
                        <CartesianGrid strokeDasharray="3 3" vertical={false} />
                        <XAxis dataKey="name" tick={{fontSize: 12}} axisLine={false} tickLine={false} />
                        <YAxis tick={{fontSize: 12}} axisLine={false} tickLine={false} prefix="$" />
                        <Tooltip 
                            formatter={(value: number, name: string) => [`$${value.toLocaleString()}`, name]}
                            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                            cursor={{ fill: '#f3f4f6' }}
                        />
                        <Legend />

                        {uniqueBanks.map((bank, index) => (
                            <Bar 
                                key={bank} 
                                dataKey={bank} 
                                fill={BANK_COLORS[bank] || DEFAULT_BANK_COLORS[index % DEFAULT_BANK_COLORS.length]} 
                                radius={[4, 4, 0, 0]} 
                            />
                        ))}
                    </BarChart>
                </ResponsiveContainer>
            ) : (
                <div className="flex items-center justify-center h-full text-gray-400 text-sm">
                    Add bills to see your monthly bank spending comparison.
                </div>
            )}
          </div>
      </div>

      {/* Bills Table */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
          {/* Table Header with Filters */}
          <div className="p-6 border-b border-gray-100 flex flex-col md:flex-row md:items-center justify-between gap-4">
              <div className="flex items-center gap-4">
                  <h3 className="text-lg font-semibold text-gray-900">Recent Bills</h3>

                  {/* Month Filters */}
                  {availableMonths.length > 0 && (
                    <div className="flex items-center bg-gray-100 p-1 rounded-lg overflow-x-auto">
                        <button
                            onClick={() => setSelectedMonthFilter('ALL')}
                            className={`px-3 py-1 text-xs font-medium rounded-md transition-all whitespace-nowrap ${
                                selectedMonthFilter === 'ALL' 
                                ? 'bg-white text-indigo-600 shadow-sm' 
                                : 'text-gray-500 hover:text-gray-700'
                            }`}
                        >
                            ALL
                        </button>
                        {availableMonths.map(month => (
                            <button
                                key={month}
                                onClick={() => setSelectedMonthFilter(month)}
                                className={`px-3 py-1 text-xs font-medium rounded-md transition-all whitespace-nowrap ${
                                    selectedMonthFilter === month 
                                    ? 'bg-white text-indigo-600 shadow-sm' 
                                    : 'text-gray-500 hover:text-gray-700'
                                }`}
                            >
                                {getMonthLabel(month)}
                            </button>
                        ))}
                    </div>
                  )}
              </div>

              <button 
                onClick={() => setIsManualModalOpen(true)}
                className="flex items-center gap-2 text-sm bg-indigo-50 text-indigo-600 px-3 py-2 rounded-lg hover:bg-indigo-100 font-medium transition-colors whitespace-nowrap"
              >
                <Plus className="w-4 h-4" />
                Add Manual Bill
              </button>
          </div>

          <div className="overflow-x-auto">
              <table className="w-full text-left text-sm text-gray-600">
                  <thead className="bg-gray-50 text-xs uppercase font-semibold text-gray-500">
                      <tr>
                          <th className="px-6 py-4">Bank / Card</th>
                          <th className="px-6 py-4">Due Date</th>
                          <th className="px-6 py-4">Amount</th>
                          <th className="px-6 py-4">Status</th>
                          <th className="px-6 py-4">Payment Info</th>
                          <th className="px-6 py-4">Actions</th>
                      </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                      {filteredBills.length === 0 ? (
                          <tr>
                              <td colSpan={6} className="px-6 py-8 text-center text-gray-400">No bills found for this period.</td>
                          </tr>
                      ) : (
                          filteredBills.map(bill => (
                              <tr key={bill.id} className="hover:bg-gray-50 transition-colors">
                                  <td className="px-6 py-4">
                                      <div className="font-medium text-gray-900">{bill.cardName}</div>
                                      <div className="text-xs text-gray-400">{bill.bankName}</div>
                                  </td>
                                  <td className="px-6 py-4">{formatDateForDisplay(bill.dueDate)}</td>
                                  <td className="px-6 py-4 font-medium">${bill.totalAmount.toFixed(2)}</td>
                                  <td className="px-6 py-4">
                                      <span className={`px-3 py-1 rounded-full text-xs font-medium ${
                                          bill.isPaid 
                                          ? 'bg-green-100 text-green-700' 
                                          : 'bg-amber-100 text-amber-700'
                                      }`}>
                                          {bill.isPaid ? 'Paid' : 'Pending'}
                                      </span>
                                  </td>
                                  <td className="px-6 py-4 text-xs">
                                      {bill.isPaid && bill.paymentDetails ? (
                                          <div>
                                              <p><span className="font-semibold text-gray-700">{bill.paymentDetails.method}</span></p>
                                              <p className="text-gray-400">Ref: {bill.paymentDetails.transactionId}</p>
                                          </div>
                                      ) : (
                                          <span className="text-gray-300">-</span>
                                      )}
                                  </td>
                                  <td className="px-6 py-4">
                                      <div className="flex items-center gap-2">
                                          {bill.filePath && (
                                              <button 
                                                  onClick={() => handleViewDocument(bill)}
                                                  className="p-2 text-indigo-500 hover:text-indigo-700 hover:bg-indigo-50 rounded-full transition-colors"
                                                  title="View Uploaded Document"
                                              >
                                                  <FileText className="w-4 h-4" />
                                              </button>
                                          )}

                                          {!bill.isPaid ? (
                                              <button 
                                                  onClick={() => setSelectedBillForPayment(bill)}
                                                  className="text-indigo-600 hover:text-indigo-800 font-medium text-xs bg-indigo-50 px-3 py-1 rounded-md hover:bg-indigo-100 transition-colors"
                                              >
                                                  Mark Paid
                                              </button>
                                          ) : (
                                            <div className="flex flex-col items-start">
                                                <button 
                                                    disabled
                                                    className="text-gray-400 font-medium text-xs cursor-not-allowed bg-gray-100 px-3 py-1 rounded-md"
                                                >
                                                    Settled
                                                </button>
                                                {/* Display Date Below Button */}
                                                {bill.paymentDetails?.paidAt && (
                                                    <span className="text-[10px] text-gray-500 mt-1 ml-1">
                                                        {formatDateForDisplay(bill.paymentDetails.paidAt)}
                                                    </span>
                                                )}
                                            </div>
                                          )}

                                          <button 
                                            onClick={() => setBillToEdit(bill)}
                                            className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                                            title="Edit Bill Details"
                                          >
                                              <Pencil className="w-4 h-4" />
                                          </button>
                                      </div>
                                  </td>
                              </tr>
                          ))
                      )}
                  </tbody>
              </table>
          </div>
      </div>

      <PaymentModal 
        bill={selectedBillForPayment}
        isOpen={!!selectedBillForPayment}
        onClose={() => setSelectedBillForPayment(null)}
        onConfirm={handlePaymentConfirm}
      />

      <ManualBillModal 
        isOpen={isManualModalOpen}
        onClose={() => setIsManualModalOpen(false)}
        onAdd={onAddBill}
      />

      <EditBillModal 
        bill={billToEdit}
        isOpen={!!billToEdit}
        onClose={() => setBillToEdit(null)}
        onSave={handleEditSave}
      />
    </div>
  );
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { User, SystemConfig } from '../types';
import { supabase } from '../lib/supabaseClient';
import { dbService } from '../services/dbService';

interface AuthContextType {
  user: User | null;
  systemConfig: SystemConfig;
  login: (email: string, password: string) => Promise<void>;
  signup: (name: string, email: string, password: string) => Promise<void>;
  logout: () => void;
  loading: boolean;
  getAllUsers: () => Promise<User[]>;
  toggleUserStatus: (userId: string) => Promise<void>;
  updateSystemConfig: (config: SystemConfig) => Promise<void>;
  changePassword: (password: string) => Promise<void>;
}

const DEFAULT_CONFIG: SystemConfig = {
  allowSignups: true,
  landingPage: {
    heroTitle: "Maximize your miles.\nMinimize the hassle.",
    heroSubtitle: "The AI-powered bill tracker designed for Singaporean credit card strategists.",
    bullets: ["Auto-extract data", "Trend analysis", "Miles Strategies"]
  }
};

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [systemConfig, setSystemConfig] = useState<SystemConfig>(DEFAULT_CONFIG);

  useEffect(() => {
    // Initial Load
    const init = async () => {
      // 1. Load System Config
      const config = await dbService.getSystemConfig();
      if (config) setSystemConfig(config);

      // 2. Check Session
      const { data: { session } } = await supabase.auth.getSession();
      if (session?.user) {
        await fetchProfile(session.user.id, session.user.email!);
      }
      setLoading(false);
    };

    init();

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (event === 'SIGNED_IN' && session?.user) {
        await fetchProfile(session.user.id, session.user.email!);
      } else if (event === 'SIGNED_OUT') {
        setUser(null);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchProfile = async (uid: string, email: string) => {
    try {
        let { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', uid)
        .single();

        // Self-Healing: If profile is missing in DB but user is Auth'd, create it.
        // This prevents FK constraints from failing in other tables (like bills).
        if (!data) {
            console.warn("User authenticated but Profile missing in DB. Attempting to self-heal...");
            const { data: newProfile, error: createError } = await supabase
                .from('profiles')
                .insert({
                    id: uid,
                    email: email,
                    name: email.split('@')[0], // Default name
                    role: 'user',
                    status: 'active'
                })
                .select()
                .single();

            if (newProfile) {
                data = newProfile;
            } else {
                console.error("Failed to auto-create profile:", createError);
            }
        }

        if (data) {
            setUser({
                id: data.id,
                email: data.email,
                name: data.name,
                role: data.role as 'admin' | 'user',
                joinedAt: data.created_at,
                status: data.status as 'active' | 'suspended'
            });
        } else {
            // Fallback purely for UI if DB insert failed (prevents white screen)
            // Note: DB writes might still fail if foreign keys are enforced.
            setUser({ id: uid, email, name: 'User', role: 'user', joinedAt: new Date().toISOString(), status: 'active' });
        }
    } catch (err) {
        console.error("Unexpected error in fetchProfile:", err);
    }
  };

  const login = async (email: string, password: string) => {
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
  };

  const signup = async (name: string, email: string, password: string) => {
    // 1. Check if signups are allowed, BUT allow the specific admin email to bypass this check
    if (!systemConfig.allowSignups && email !== 'jeratomise@gmail.com') {
        throw new Error("Registrations are currently disabled by the administrator.");
    }

    // 2. Create Auth User
    const { data, error } = await supabase.auth.signUp({
      email,
      password,
      options: { data: { name } }
    });

    if (error) throw error;

    // 3. Create Profile Entry manually
    if (data.user) {
        const isAdmin = email === 'jeratomise@gmail.com';

        await supabase.from('profiles').insert({
            id: data.user.id,
            email: email,
            name: name,
            role: isAdmin ? 'admin' : 'user'
        });
    }
  };

  const logout = async () => {
    await supabase.auth.signOut();
  };

  // --- Admin Functions ---
  const getAllUsers = async (): Promise<User[]> => {
      const { data, error } = await supabase.from('profiles').select('*');
      if (error) throw error;
      return data.map((u: any) => ({
          id: u.id,
          email: u.email,
          name: u.name,
          role: u.role,
          status: u.status,
          joinedAt: u.created_at
      }));
  };

  const toggleUserStatus = async (userId: string) => {
      // Fetch current status first
      const { data } = await supabase.from('profiles').select('status').eq('id', userId).single();
      const newStatus = data?.status === 'active' ? 'suspended' : 'active';

      const { error } = await supabase.from('profiles').update({ status: newStatus }).eq('id', userId);
      if (error) throw error;
  };

  const updateSystemConfig = async (config: SystemConfig) => {
      await dbService.updateSystemConfig(config);
      setSystemConfig(config);
  };

  const changePassword = async (password: string) => {
      const { error } = await supabase.auth.updateUser({ password });
      if (error) throw error;
  };

  return (
    <AuthContext.Provider value={{ 
        user, 
        systemConfig,
        login, 
        signup, 
        logout, 
        loading,
        getAllUsers,
        toggleUserStatus,
        updateSystemConfig,
        changePassword
    }}>
      {children}
    </AuthContext.Provider>
  );
};

