export const extractBillData = async (base64Data: string, mimeType: string = "image/png"): Promise<AIExtractionResponse> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data,
            },
          },
          {
            text: `Analyze this credit card statement document (PDF or Image). It may contain multiple different cards (e.g. a consolidated bank statement).

            CRITICAL INSTRUCTION FOR SINGAPORE BANKS (DBS, UOB, CITIBANK, AMEX):

            1. **DBS / POSB Statements**: 
               - The detailed breakdown of *each* card and its "Total Outstanding Balance" is often located in a summary table on the **LAST PAGE** of the PDF (labeled "TOTAL OUTSTANDING BALANCE" or "Card Account Summary"). 
               - Do NOT just look at the first page. Check the last page.
               - Extract every card listed (e.g. "DBS YUU", "DBS Woman's World", "DBS Vantage").

            2. **Citibank / UOB**: 
               - Look for "Account Summary" or "Payment Slip" usually on the first 1-2 pages.

            3. **American Express (Amex)**:
               - Look for "Closing Balance" and "Due Date" on the first page.
               - Date Format Warning: Amex often uses DD.MM.YYYY (e.g. 14.12.2025). Convert this strictly to YYYY-MM-DD (2025-12-14).

            DATA EXTRACTION RULES:
            - **Card Name**: Be precise (e.g. "Citi Rewards", "UOB Lady's Card", "DBS Woman's World"). If generic, use the Bank Name + Card Type.
            - **Total Amount**: Use the "Statement Balance", "Closing Balance", or "Total Outstanding Balance". Do NOT use "Minimum Payment".
            - **Due Date**: Look for "Payment Due Date". Convert to YYYY-MM-DD.
            - **Statement Date**: Look for "Statement Date" or "Date of Issue".
            - **Transactions**: Scan pages for transaction lists. Assign them to the correct card if multiple cards exist. If you cannot map transactions to a specific card in a multi-card statement, assign them to the card with the matching total.

            Return JSON format with a 'bills' array.`,
          },
        ],
      },
      config: {
        systemInstruction: MILELION_SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            bills: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  bankName: { type: Type.STRING },
                  cardName: { type: Type.STRING },
                  totalAmount: { type: Type.NUMBER },
                  dueDate: { type: Type.STRING, description: "YYYY-MM-DD format" },
                  statementDate: { type: Type.STRING, description: "YYYY-MM-DD format" },
                  transactions: {
                    type: Type.ARRAY,
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        date: { type: Type.STRING, description: "YYYY-MM-DD format" },
                        description: { type: Type.STRING },
                        amount: { type: Type.NUMBER },
                        category: { type: Type.STRING },
                      },
                    },
                  },
                },
                required: ["bankName", "totalAmount", "dueDate", "transactions"],
              },
            },
          },
        },
      },
    });

    if (response.text) {
      return JSON.parse(response.text) as AIExtractionResponse;
    }
    throw new Error("Empty response from Gemini");
  } catch (error) {
    console.error("Error extracting bill data:", error);
    throw error;
  }
};

