import React, { createContext, useContext, useState, useEffect } from 'react';
import { User, SystemConfig } from '../types';
import { supabase } from '../lib/supabaseClient';
import { dbService } from '../services/dbService';

interface AuthContextType {
  user: User | null;
  systemConfig: SystemConfig;
  login: (email: string, password: string) => Promise<void>;
  signup: (name: string, email: string, password: string) => Promise<void>;
  logout: () => void;
  loading: boolean;
  getAllUsers: () => Promise<User[]>;
  toggleUserStatus: (userId: string) => Promise<void>;
  updateSystemConfig: (config: SystemConfig) => Promise<void>;
  changePassword: (password: string) => Promise<void>;
}

const DEFAULT_CONFIG: SystemConfig = {
  allowSignups: true,
  landingPage: {
    heroTitle: "Financial Clarity.\nFor the Elite.",
    heroSubtitle: "CreditTrack by EliteX.CC: The AI-powered bill tracker designed for Singapore's top tier.",
    bullets: ["Auto-extract data", "Miles Optimization Strategy", "Consolidated Wealth View"]
  }
};

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [systemConfig, setSystemConfig] = useState<SystemConfig>(DEFAULT_CONFIG);

  useEffect(() => {
    // Initial Load
    const init = async () => {
      // 1. Load System Config
      const config = await dbService.getSystemConfig();
      if (config) setSystemConfig(config);

      // 2. Check Session
      const { data: { session } } = await supabase.auth.getSession();
      if (session?.user) {
        await fetchProfile(session.user.id, session.user.email!);
      }
      setLoading(false);
    };

    init();

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (event === 'SIGNED_IN' && session?.user) {
        await fetchProfile(session.user.id, session.user.email!);
      } else if (event === 'SIGNED_OUT') {
        setUser(null);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchProfile = async (uid: string, email: string) => {
    try {
        let { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', uid)
        .single();

        // Self-Healing: If profile is missing in DB but user is Auth'd, create it.
        // This prevents FK constraints from failing in other tables (like bills).
        if (!data) {
            console.warn("User authenticated but Profile missing in DB. Attempting to self-heal...");
            const { data: newProfile, error: createError } = await supabase
                .from('profiles')
                .insert({
                    id: uid,
                    email: email,
                    name: email.split('@')[0], // Default name
                    role: 'user',
                    status: 'active'
                })
                .select()
                .single();

            if (newProfile) {
                data = newProfile;
            } else {
                console.error("Failed to auto-create profile:", createError);
            }
        }

        if (data) {
            setUser({
                id: data.id,
                email: data.email,
                name: data.name,
                role: data.role as 'admin' | 'user',
                joinedAt: data.created_at,
                status: data.status as 'active' | 'suspended'
            });
        } else {
            // Fallback purely for UI if DB insert failed (prevents white screen)
            // Note: DB writes might still fail if foreign keys are enforced.
            setUser({ id: uid, email, name: 'User', role: 'user', joinedAt: new Date().toISOString(), status: 'active' });
        }
    } catch (err) {
        console.error("Unexpected error in fetchProfile:", err);
    }
  };

  const login = async (email: string, password: string) => {
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
  };

  const signup = async (name: string, email: string, password: string) => {
    // 1. Check if signups are allowed, BUT allow the specific admin email to bypass this check
    if (!systemConfig.allowSignups && email !== 'jeratomise@gmail.com') {
        throw new Error("Registrations are currently disabled by the administrator.");
    }

    // 2. Create Auth User
    const { data, error } = await supabase.auth.signUp({
      email,
      password,
      options: { data: { name } }
    });

    if (error) throw error;

    // 3. Create Profile Entry manually
    if (data.user) {
        const isAdmin = email === 'jeratomise@gmail.com';

        await supabase.from('profiles').insert({
            id: data.user.id,
            email: email,
            name: name,
            role: isAdmin ? 'admin' : 'user'
        });
    }
  };

  const logout = async () => {
    await supabase.auth.signOut();
  };

  // --- Admin Functions ---
  const getAllUsers = async (): Promise<User[]> => {
      const { data, error } = await supabase.from('profiles').select('*');
      if (error) throw error;
      return data.map((u: any) => ({
          id: u.id,
          email: u.email,
          name: u.name,
          role: u.role,
          status: u.status,
          joinedAt: u.created_at
      }));
  };

  const toggleUserStatus = async (userId: string) => {
      // Fetch current status first
      const { data } = await supabase.from('profiles').select('status').eq('id', userId).single();
      const newStatus = data?.status === 'active' ? 'suspended' : 'active';

      const { error } = await supabase.from('profiles').update({ status: newStatus }).eq('id', userId);
      if (error) throw error;
  };

  const updateSystemConfig = async (config: SystemConfig) => {
      await dbService.updateSystemConfig(config);
      setSystemConfig(config);
  };

  const changePassword = async (password: string) => {
      const { error } = await supabase.auth.updateUser({ password });
      if (error) throw error;
  };

  return (
    <AuthContext.Provider value={{ 
        user, 
        systemConfig,
        login, 
        signup, 
        logout, 
        loading,
        getAllUsers,
        toggleUserStatus,
        updateSystemConfig,
        changePassword
    }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import React, { useState, useEffect } from 'react';
import { UserSettings } from '../types';
import { useAuth } from '../contexts/AuthContext';
import { Save, Bell, Mail, Clock, Lock, CheckCircle, AlertCircle, Loader2 } from 'lucide-react';

export const Settings: React.FC = () => {
  const { changePassword, user } = useAuth();
  const [settings, setSettings] = useState<UserSettings>({
    email: '',
    notificationFrequency: 'weekly',
    reminderEnabled: true
  });
  const [saved, setSaved] = useState(false);

  // Password State
  const [passwords, setPasswords] = useState({ new: '', confirm: '' });
  const [passMsg, setPassMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);
  const [isChangingPassword, setIsChangingPassword] = useState(false);

  useEffect(() => {
    const savedSettings = localStorage.getItem('credittrack_settings');
    if (savedSettings) {
      setSettings(JSON.parse(savedSettings));
    }
    // Pre-fill email from auth user if available and empty settings
    if (user?.email && (!savedSettings)) {
        setSettings(prev => ({ ...prev, email: user.email }));
    }
  }, [user]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    localStorage.setItem('credittrack_settings', JSON.stringify(settings));
    setSaved(true);
    setTimeout(() => setSaved(false), 3000);
  };

  const handleChangePassword = async (e: React.FormEvent) => {
      e.preventDefault();
      setPassMsg(null);

      if (passwords.new.length < 6) {
          setPassMsg({ type: 'error', text: 'Password must be at least 6 characters.' });
          return;
      }
      if (passwords.new !== passwords.confirm) {
          setPassMsg({ type: 'error', text: 'Passwords do not match.' });
          return;
      }

      setIsChangingPassword(true);

      try {
          await changePassword(passwords.new);
          setPassMsg({ type: 'success', text: 'Password updated successfully.' });
          setPasswords({ new: '', confirm: '' });
      } catch (err: any) {
          console.error("Password update error:", err);
          setPassMsg({ 
              type: 'error', 
              text: err.message || 'Failed to update password. Please try again.' 
          });
      } finally {
          setIsChangingPassword(false);
      }
  };

  return (
    <div className="max-w-2xl mx-auto animate-fade-in pb-10">
      <header className="mb-8">
        <h1 className="text-2xl font-bold text-gray-900">App Settings</h1>
        <p className="text-gray-500">Configure your notifications and preferences.</p>
      </header>

      <div className="space-y-8">
          {/* General Preferences */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            <form onSubmit={handleSave} className="p-6 space-y-8">

            {/* Email Section */}
            <div className="space-y-4">
                <div className="flex items-center gap-2 text-gray-900 font-semibold pb-2 border-b border-gray-100">
                <Mail className="w-5 h-5 text-indigo-600" />
                <h3>Contact Information</h3>
                </div>
                <div className="grid gap-2">
                <label className="text-sm font-medium text-gray-700">Email Address</label>
                <input 
                    type="email"
                    required
                    placeholder="jerome@example.com"
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    value={settings.email}
                    onChange={(e) => setSettings({...settings, email: e.target.value})}
                />
                <p className="text-xs text-gray-500">We'll use this to address the payment reminder drafts.</p>
                </div>
            </div>

            {/* Notification Section */}
            <div className="space-y-4">
                <div className="flex items-center gap-2 text-gray-900 font-semibold pb-2 border-b border-gray-100">
                <Bell className="w-5 h-5 text-indigo-600" />
